#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\Users\Informatica\Documents\CRUD TS\node_modules\.pnpm\jest@29.5.0_@types+node@25._457b2035fdb5a237a7788327bbccb78f\node_modules\jest\node_modules;C:\Users\Informatica\Documents\CRUD TS\node_modules\.pnpm\jest@29.5.0_@types+node@25._457b2035fdb5a237a7788327bbccb78f\node_modules;C:\Users\Informatica\Documents\CRUD TS\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/Users/Informatica/Documents/CRUD TS/node_modules/.pnpm/jest@29.5.0_@types+node@25._457b2035fdb5a237a7788327bbccb78f/node_modules/jest/node_modules:/mnt/c/Users/Informatica/Documents/CRUD TS/node_modules/.pnpm/jest@29.5.0_@types+node@25._457b2035fdb5a237a7788327bbccb78f/node_modules:/mnt/c/Users/Informatica/Documents/CRUD TS/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../../bin/jest.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../../bin/jest.js" $args
  }
  $ret=$LASTEXITCODE
